#include <bits/stdc++.h>
using namespace std;

int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];

    long long inv_count = 0;
    function<void(vector<int>&)> merge_sort = [&](vector<int>& arr) {
        if (arr.size() <= 1) return;
        int mid = arr.size() / 2;
        vector<int> left(arr.begin(), arr.begin() + mid);
        vector<int> right(arr.begin() + mid, arr.end());
        merge_sort(left);
        merge_sort(right);
        int i = 0, j = 0, k = 0;
        while (i < left.size() && j < right.size()) {
            if (left[i] <= right[j]) {
                arr[k++] = left[i++];
            } else {
                arr[k++] = right[j++];
                inv_count += left.size() - i;
            }
        }
        while (i < left.size()) arr[k++] = left[i++];
        while (j < right.size()) arr[k++] = right[j++];
    };

    merge_sort(arr);
    cout << inv_count << endl;
    return 0;
}
